log-to-eventhub.expression:
@{
            return Newtonsoft.Json.JsonConvert.SerializeObject(new {
              event_type       = "AUTH_FAILURE",
              pci_requirement  = "PCI DSS v4.0 Req 10.2.1.4",
              timestamp        = DateTime.UtcNow.ToString("o"),
              user_id          = (string)context.Variables["pci-audit-user-id"],
              client_ip        = (string)context.Variables["pci-audit-client-ip"],
              api              = (string)context.Variables["pci-audit-api"],
              request_path     = (string)context.Variables["pci-audit-path"],
              request_id       = (string)context.Variables["pci-audit-request-id"],
              outcome          = "AUTH_FAILURE",
              http_status_code = 401,
              pci_audit_policy = true,
              // Alert: repeated AUTH_FAILURE events should trigger SIEM alert per PCI DSS Req 10.7
              alert_on_repeat  = true
            });
          }

@{
        return Newtonsoft.Json.JsonConvert.SerializeObject(new {
          event_type       = "GATEWAY_ERROR",
          pci_requirement  = "PCI DSS v4.0 Req 10.2.1.7",
          timestamp        = DateTime.UtcNow.ToString("o"),
          user_id          = (string)context.Variables["pci-audit-user-id"],
          subscription_id  = (string)context.Variables["pci-audit-sub-id"],
          client_ip        = (string)context.Variables["pci-audit-client-ip"],
          api              = (string)context.Variables["pci-audit-api"],
          operation        = (string)context.Variables["pci-audit-operation"],
          request_path     = (string)context.Variables["pci-audit-path"],
          request_id       = (string)context.Variables["pci-audit-request-id"],
          // Error source and code only — NOT the full message (may reference CHD)
          error_source     = context.LastError?.Source ?? "unknown",
          error_reason     = context.LastError?.Reason ?? "unknown",
          outcome          = "ERROR",
          pci_audit_policy = true,
          _body_logged     = false
        });
      }
